const kpis = $('Query KPIs').first().json;
const categorias = $('Query Top Categorías').all().map(i => i.json);
const metricas = $('Query Métricas').first().json;

let topCats = '';
for (let i = 0; i < categorias.length; i++) {
  const emoji = ['🥇', '🥈', '🥉', '4️⃣', '5️⃣'][i];
  topCats += `${emoji} ${categorias[i].categoria}: R$ ${Number(categorias[i].revenue).toLocaleString('pt-BR', {minimumFractionDigits: 2})}\n`;
}

const mensaje = `🛒 *OLIST E-COMMERCE — REPORTE*
━━━━━━━━━━━━━━━━━━━━━━

📊 *KPIs Generales*
├ Total Órdenes: *${Number(kpis.total_ordenes).toLocaleString()}*
├ Clientes Únicos: *${Number(kpis.total_clientes).toLocaleString()}*
├ Revenue Total: *R$ ${Number(kpis.revenue_total).toLocaleString('pt-BR', {minimumFractionDigits: 2})}*
└ Ticket Promedio: *R$ ${Number(kpis.ticket_promedio).toLocaleString('pt-BR', {minimumFractionDigits: 2})}*

🏆 *Top 5 Categorías por Revenue*
${topCats}
📦 *Logística y Entregas*
├ Tiempo promedio de entrega: *${metricas.dias_entrega} días*
├ Entregas tardías: *${metricas.pct_entregas_tardias}%*
└ Entregas a tiempo: *${(100 - Number(metricas.pct_entregas_tardias)).toFixed(2)}%*

⚠️ *Incidencias y Satisfacción*
├ Cancelaciones: *${metricas.pct_canceladas}%*
├ Reviews negativas (1-2): *${metricas.pct_reviews_negativas}%*
└ Reviews positivas (4-5): *${(100 - Number(metricas.pct_reviews_negativas)).toFixed(1)}%*

💡 *Insights Clave*
- La insatisfacción real (~15%) es 10x mayor que las cancelaciones (0.6%)
- El cuello de botella logístico está en el tránsito (${metricas.dias_entrega} días promedio)
- health\\_beauty lidera en revenue pero bed\\_bath\\_table en volumen de órdenes

━━━━━━━━━━━━━━━━━━━━━━
📈 *Dashboard interactivo:*
http://localhost:8501

🤖 _Generado automáticamente por el pipeline Olist_`;

return [{ json: { mensaje } }];
